  vec4 cc_time;
  mediump vec4 cc_screenSize;
  mediump vec4 cc_screenScale;
};
uniform CCLocal {
  mat4 cc_matWorld;
  mat4 cc_matWorldIT;
};
in vec3 a_position;
in vec4 a_color;
out vec4 v_color;
in vec2 a_uv0;
out vec2 v_uv0;
void main () {
  vec4 pos = vec4(a_position, 1);
  pos = cc_matViewProj * pos;
  v_uv0 = a_uv0;
  v_color = a_color;
  gl_Position = pos;
}

glsl3.frag:
precision highp float;
#if USE_ALPHA_TEST
  uniform ALPHA_TEST {
    float alphaThreshold;
  };
#endif
void ALPHA_TEST (in vec4 color) {
  #if USE_ALPHA_TEST
      if (color.a < alphaThreshold) discard;
  #endif
}
void ALPHA_TEST (in float alpha) {
  #if USE_ALPHA_TEST
      if (alpha < alphaThreshold) discard;
  #endif
}
uniform CCGlobal {
  mat4 cc_matView;
  mat4 cc_matViewInv;
  mat4 cc_matProj;
  mat4 cc_matProjInv;
  mat4 cc_matViewProj;
  mat4 cc_matViewProjInv;
  vec4 cc_cameraPos;
  vec4 cc_time;
  mediump vec4 cc_screenSize;
  mediump vec4 cc_screenScale;
};
in vec4 v_color;
in vec2 v_uv0;
uniform sampler2D texture;
uniform sampler2D noiseTexture;
uniform Constant {
  vec2 speed;
  vec2 tiling;
  vec2 dispSpeed;
  float feather;
  float distortion;
  float rotation;
  float polarStrength;
  float waveAmp;
  float waveFreq;
  float waveSpeed;
  float dispStrength;
};
vec2 rotateUV(vec2 uv, float angleDeg) {
  float angleRad = radians(angleDeg);
  float c = cos(angleRad);
  float s = sin(angleRad);
  vec2 centered = uv - 0.5;
  vec2 rotated = vec2(
    centered.x * c - centered.y * s,
    centered.x * s + centered.y * c
  );
  return rotated + 0.5;
}
void main () {
  vec2 uvNormalized = v_uv0 - 0.5;
  float r2 = dot(uvNormalized, uvNormalized);
  uvNormalized = uvNormalized * (1.0 + distortion * r2);
  float phi = atan(uvNormalized.y, uvNormalized.x);
  float r = length(uvNormalized);
  float u_polar = phi / (2.0 * 3.14159265) + 0.5;
  float v_polar = r * 2.0;
  vec2 polarUV = vec2(u_polar, v_polar);
  vec2 cartesianUV = uvNormalized + 0.5;
  vec2 currentUV = mix(cartesianUV, polarUV, polarStrength);
  currentUV = rotateUV(currentUV, rotation);
  float waveOffset = sin(currentUV.y * waveFreq + cc_time.x * waveSpeed) * waveAmp;
  currentUV.x += waveOffset;
  vec2 noiseUV = v_uv0 + dispSpeed * cc_time.x;
  vec4 noiseColor = texture2D(noiseTexture, fract(noiseUV));
  vec2 dispOffset = (noiseColor.rg - 0.5) * dispStrength;
  currentUV += dispOffset;
  vec2 finalUV = currentUV * tiling + speed * cc_time.x;
  finalUV = fract(finalUV);
  vec4 o = texture2D(texture, finalUV);
  o *= v_color;
  float dist = distance(v_uv0, vec2(0.5));
  float radius = 0.5;
  float rawFade = smoothstep(radius - feather, radius, dist);
  o.a *= (1.0 - rawFade);
  ALPHA_TEST(o);
  gl_FragColor = o;
}

