glsl3.frag:
precision highp float;
uniform sampler2D texture;
in vec2 v_uv0;
in vec4 v_light;
#if USE_TINT
  in vec4 v_dark;
#endif
#if USE_ALPHA_TEST
  uniform ALPHA_TEST {
    float alphaThreshold;
  };
#endif
void ALPHA_TEST (in vec4 color) {
  #if USE_ALPHA_TEST
      if (color.a < alphaThreshold) discard;
  #endif
}
void ALPHA_TEST (in float alpha) {
  #if USE_ALPHA_TEST
      if (alpha < alphaThreshold) discard;
  #endif
}
uniform CCGlobal {
  mat4 cc_matView;
  mat4 cc_matViewInv;
  mat4 cc_matProj;
  mat4 cc_matProjInv;
  mat4 cc_matViewProj;
  mat4 cc_matViewProjInv;
  vec4 cc_cameraPos;
  vec4 cc_time;
  mediump vec4 cc_screenSize;
  mediump vec4 cc_screenScale;
};
uniform sampler2D noiseTexture;
uniform Constant {
  vec4 burnColor;
  vec2 dispSpeed;
  vec2 textureScrollSpeed;
  float dispStrength;
  float dissolveThreshold;
  float burnWidth;
  float edgeFeather;
};
void main () {
  vec2 uvHalf = vec2(0.5, 0.5);
  vec2 noiseMove = dispSpeed * cc_time.x;
  vec2 noiseUV = fract(v_uv0 + noiseMove);
  vec4 noiseCol = texture2D(noiseTexture, noiseUV);
  vec2 dispOffset = (noiseCol.rg - uvHalf) * dispStrength;
  vec2 distortedUV = v_uv0 + dispOffset;
  vec2 texScrollOffset = textureScrollSpeed * cc_time.x;
  vec2 finalUV = fract(distortedUV + texScrollOffset);
  vec4 texColor = vec4(1.0);
  vec4 texture_tmp = texture(texture, finalUV);
  #if CC_USE_ALPHA_ATLAS_texture
      texture_tmp.a *= texture(texture, finalUV + vec2(0, 0.5)).r;
  #endif
  #if INPUT_IS_GAMMA
    texColor.rgb *= (texture_tmp.rgb * texture_tmp.rgb);
    texColor.a *= texture_tmp.a;
  #else
    texColor *= texture_tmp;
  #endif
  float noiseVal = noiseCol.r;
  if (noiseVal < dissolveThreshold) {
    discard;
  }
  float thresholdWithWidth = dissolveThreshold + burnWidth;
  if (noiseVal < thresholdWithWidth) {
     float t = (noiseVal - dissolveThreshold) / burnWidth;
     t = smoothstep(0.0, 1.0, t);
     vec3 mixedRGB = mix(burnColor.rgb, texColor.rgb, t);
     texColor.rgb = mixedRGB;
  }
  vec2 borderDists = min(v_uv0, vec2(1.0, 1.0) - v_uv0);
  float fadeX = smoothstep(0.0, edgeFeather, borderDists.x);
  float fadeY = smoothstep(0.0, edgeFeather, borderDists.y);
  float borderMask = fadeX * fadeY;
  texColor.a = texColor.a * borderMask;
  vec4 finalColor;
  #if USE_TINT
    finalColor.a = v_light.a * texColor.a;
    finalColor.rgb = ((texColor.a - 1.0) * v_dark.a + 1.0 - texColor.rgb) * v_dark.rgb + texColor.rgb * v_light.rgb;
  #else
    finalColor = texColor * v_light;
  #endif
  ALPHA_TEST(finalColor);
  gl_FragColor = finalColor;
}

